member.example:
Bind the Image fillAmount property using a serialized binder field — the target Image is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ImageFillBinder _progress;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _progress;
    }


Bind the Image fillAmount property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Image _image;
        
        private ImageFillBinder Progress =>
            new(_image);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _progress;
    }

Switch the Image fillAmount between two values using a serialized binder field — the target Image is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ImageFillSwitcherBinder _isComplete;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isComplete;
    }


Switch the Image fillAmount between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Image _image;
        
        [SerializeField]
        private float _filledAmount;
        
        [SerializeField]
        private float _emptyAmount;
        
        private ImageFillSwitcherBinder IsComplete => new(
            _image, _filledAmount, _emptyAmount, null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isComplete;
    }
